<script setup>
import { computed, defineProps } from 'vue'

const props = defineProps({
	value: String,
})

const colorStops = [
	{ t: 0.0, hex: '#0066FF' },
	{ t: 0.25, hex: '#EAF7FF' },
	{ t: 0.5, hex: '#FFD400' },
	{ t: 0.75, hex: '#FF7A00' },
	{ t: 1.0, hex: '#FF0000' },
]

const hexToRgb = (hex) => {
	const clean = hex.replace('#', '')
	const r = parseInt(clean.slice(0, 2), 16)
	const g = parseInt(clean.slice(2, 4), 16)
	const b = parseInt(clean.slice(4, 6), 16)
	return { r, g, b }
}

const lerp = (a, b, t) => a + (b - a) * t

const lerpColor = (fromHex, toHex, t) => {
	const a = hexToRgb(fromHex)
	const b = hexToRgb(toHex)
	const r = Math.round(lerp(a.r, b.r, t))
	const g = Math.round(lerp(a.g, b.g, t))
	const bch = Math.round(lerp(a.b, b.b, t))
	return `rgb(${r}, ${g}, ${bch})`
}

const currentTempY = computed(() => {
	const tempStr = props.value.replace('°C', '').replace(',', '.')
	const temp = parseFloat(tempStr)
	const clampedTemp = Math.max(-15, Math.min(40, temp))

	const tempPoints = [
		{ temp: -15, y: 136.422653 },
		{ temp: -10, y: 146.323227 },
		{ temp: -5, y: 136.422653 },
		{ temp: 0, y: 126.522079 },
		{ temp: 5, y: 116.6119695 },
		{ temp: 10, y: 106.70186 },
		{ temp: 15, y: 96.7786695 },
		{ temp: 20, y: 86.855479 },
		{ temp: 25, y: 76.95011 },
		{ temp: 30, y: 67.044741 },
		{ temp: 35, y: 57.108956 },
		{ temp: 40, y: 47.173171 }
	]

	for (let i = 0; i < tempPoints.length - 1; i++) {
		const t1 = tempPoints[i].temp, y1 = tempPoints[i].y
		const t2 = tempPoints[i + 1].temp, y2 = tempPoints[i + 1].y
		if (clampedTemp >= t1 && clampedTemp <= t2) {
			return y1 + (clampedTemp - t1) * (y2 - y1) / (t2 - t1)
		}
	}
	return 120.701246
})

const fillColor = computed(() => {
	const tempStr = props.value.replace('°C', '').replace(',', '.')
	const temp = parseFloat(tempStr)
	const clampedTemp = Math.max(-15, Math.min(40, temp))
	const t = (clampedTemp + 15) / 55
	for (let i = 0; i < colorStops.length - 1; i++) {
		const s1 = colorStops[i]
		const s2 = colorStops[i + 1]
		if (t >= s1.t && t <= s2.t) {
			const localT = (t - s1.t) / (s2.t - s1.t)
			return lerpColor(s1.hex, s2.hex, localT)
		}
	}
	return colorStops[colorStops.length - 1].hex
})
</script>
